    pericias: ["Acrobacia +18", "Atletismo +12", "Diplomacia +12", "Enganação +12", "Furtividade +16", "Intimidação +14", "Ladinagem +12"],
    equipamentos: ["Navalha (conta como uma adaga veloz)", "Sapatos de camurça aprimorados", "Tabardo aprimorado", "Traje da corte", "Mosquete preciso de adamante", "20 balas maciças"],
    tesouro: "Dobro."
