    nd: "2",
    tipo: "Humanoide (gnoll)",
    tamanho: "Médio",
    papel: "Especial",
    origin: "Ameaças de Arton",
    tema: "Gnolls",
    iniciativa: 2,
    percepcao: 6,
    defesa: 17,
    fort: 7,
    ref: 2,
    von: 13,
