    pv: 30,
    deslocamento: "Natação 12m (8q)",
    habilidades: [
      "Ataque Sônico (Padrão): O platan causa 6d6 pontos de dano de impacto em uma criatura em alcance curto (Fort CD 16 reduz à metade)."
    ],
    for: "1",
    des: "3",
